import{_ as i,c as r,o as n,a5 as l,j as a}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.57：桌面端大优化","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.57.md","filePath":"changelog/v1.1.57.md","lastUpdated":1772014034000}'),d={name:"changelog/v1.1.57.md"};function h(t,e,o,s,c,b){return n(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="v1-1-57-桌面端大优化" tabindex="-1">v1.1.57：桌面端大优化 <a class="header-anchor" href="#v1-1-57-桌面端大优化" aria-label="Permalink to “v1.1.57：桌面端大优化”">​</a></h1><p><strong>发布日期</strong>：2026年2月11日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新 <strong>大幅优化桌面应用体验</strong>，修复终端复制粘贴、Windows 适配、Wayland 支持等问题，同时改进了上下文压缩的可靠性。</p><hr><h2 id="新功能-wsl-后端模式" tabindex="-1">新功能：WSL 后端模式 <a class="header-anchor" href="#新功能-wsl-后端模式" aria-label="Permalink to “新功能：WSL 后端模式”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>桌面版 OpenCode 现在支持 <strong>WSL 后端模式</strong>，可以在 Windows 上通过 WSL 运行 OpenCode，获得更好的兼容性。</p><h3 id="wsl-后端模式是什么" tabindex="-1">WSL 后端模式是什么？ <a class="header-anchor" href="#wsl-后端模式是什么" aria-label="Permalink to “WSL 后端模式是什么？”">​</a></h3><p>如果你在 Windows 上使用 WSL（Windows Subsystem for Linux），可以让桌面版 OpenCode 在 WSL 环境中运行，而不是直接在 Windows 上运行。</p><h3 id="好处是什么" tabindex="-1">好处是什么？ <a class="header-anchor" href="#好处是什么" aria-label="Permalink to “好处是什么？”">​</a></h3><ul><li>更好的 Linux 工具链兼容性</li><li>文件系统行为与 Linux 一致</li><li>避免一些 Windows 特有的问题</li></ul><hr><h2 id="改进-上下文压缩更可靠" tabindex="-1">改进：上下文压缩更可靠 <a class="header-anchor" href="#改进-上下文压缩更可靠" aria-label="Permalink to “改进：上下文压缩更可靠”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>在长对话中，OpenCode 会自动压缩上下文以节省 token。但有时压缩不够可靠，可能导致信息丢失。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><ul><li>增加了预留 token 缓冲区，为输入窗口压缩留出足够空间</li><li>添加了更多上下文溢出的处理场景</li><li>移除了过度纠正的情况</li></ul><hr><h2 id="改进-tui-侧边栏默认自动" tabindex="-1">改进：TUI 侧边栏默认自动 <a class="header-anchor" href="#改进-tui-侧边栏默认自动" aria-label="Permalink to “改进：TUI 侧边栏默认自动”">​</a></h2><h3 id="变化" tabindex="-1">变化 <a class="header-anchor" href="#变化" aria-label="Permalink to “变化”">​</a></h3><p>TUI（终端界面）的会话侧边栏现在默认为「自动」模式，根据终端宽度自动显示或隐藏。</p><hr><h2 id="问题修复-桌面端多项改进" tabindex="-1">问题修复：桌面端多项改进 <a class="header-anchor" href="#问题修复-桌面端多项改进" aria-label="Permalink to “问题修复：桌面端多项改进”">​</a></h2><h3 id="终端复制粘贴" tabindex="-1">终端复制粘贴 <a class="header-anchor" href="#终端复制粘贴" aria-label="Permalink to “终端复制粘贴”">​</a></h3><p>之前桌面应用的终端复制粘贴功能有问题，现在已修复。</p><h3 id="windows-应用适配" tabindex="-1">Windows 应用适配 <a class="header-anchor" href="#windows-应用适配" aria-label="Permalink to “Windows 应用适配”">​</a></h3><ul><li>改善了 Windows 上的应用分辨率检测</li><li>优化了 UI 加载状态</li><li>修复了复制路径按钮样式</li></ul><h3 id="wayland-支持" tabindex="-1">Wayland 支持 <a class="header-anchor" href="#wayland-支持" aria-label="Permalink to “Wayland 支持”">​</a></h3><p>桌面应用现在会从配置中读取 Wayland 偏好设置，更好地支持 Linux Wayland 显示服务器。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>使用桌面版</td><td>✅ 升级</td></tr><tr><td>Windows 用户</td><td>✅ 强烈推荐</td></tr><tr><td>只用终端版</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',35),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),l('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core-核心" tabindex="-1">Core（核心） <a class="header-anchor" href="#core-核心" aria-label="Permalink to “Core（核心）”">​</a></h3><ul><li>添加更多上下文溢出处理场景，移除过度纠正</li><li>确保压缩更可靠，增加预留 token 缓冲区</li><li>改进 /review 提示词，更明确地检测行为变化</li><li>改进 Amazon Bedrock 检查，支持容器凭证</li></ul><h3 id="tui-终端界面" tabindex="-1">TUI（终端界面） <a class="header-anchor" href="#tui-终端界面" aria-label="Permalink to “TUI（终端界面）”">​</a></h3><ul><li>会话侧边栏默认为自动模式</li></ul><h3 id="desktop-桌面应用" tabindex="-1">Desktop（桌面应用） <a class="header-anchor" href="#desktop-桌面应用" aria-label="Permalink to “Desktop（桌面应用）”">​</a></h3><ul><li>修复终端复制粘贴功能</li><li>修复复制路径按钮样式</li><li>使用 tracing 进行日志记录</li><li>增强 Windows 应用分辨率和 UI 加载状态</li><li>改进桌面应用服务器启动弹性</li><li>从配置中读取 Wayland 偏好</li><li>添加 WSL 后端模式</li></ul><h3 id="sdk" tabindex="-1">SDK <a class="header-anchor" href="#sdk" aria-label="Permalink to “SDK”">​</a></h3><ul><li>在 v1 SDK HTTP 头中编码非 ASCII 目录路径</li></ul><h3 id="社区贡献" tabindex="-1">社区贡献 <a class="header-anchor" href="#社区贡献" aria-label="Permalink to “社区贡献”">​</a></h3><ul><li>@OpeOginni：改进 Amazon Bedrock 检查支持容器凭证</li><li>@Brendonovich：添加 WSL 后端模式、Wayland 偏好、tracing 日志</li><li>@neriousy：增强 Windows 应用分辨率和 UI 加载状态</li><li>@MrMushrooooom：修复非 ASCII 目录路径编码</li><li>@ariane-emory：移除迁移到 1.0 文档</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const u=i(d,[["render",h]]);export{m as __pageData,u as default};
